document.addEventListener('DOMContentLoaded', () => {
  initSite('shop.html');
  renderCheckoutSummary();
  initCheckoutForm();
});
function renderCheckoutSummary() {
  Cart.load();
  const container = document.getElementById('checkout-order-summary');
  if (!container) return;
  if (Cart.items.length === 0) {
    container.innerHTML = `
      <p style="text-align:center;color:var(--text-muted);padding:20px">
        Your cart is empty. <a href="shop.html" style="color:var(--saffron)">Shop now</a>
      </p>`;
    return;
  }
  const subtotal = Cart.total();
  const delivery = subtotal >= 599 ? 0 : 60;
  const total    = subtotal + delivery;
  container.innerHTML = `
    <div style="display:flex;flex-direction:column;gap:12px;margin-bottom:16px">
      ${Cart.items.map(i => `
        <div style="display:flex;gap:12px;align-items:center">
          <img src="${i.image}" style="width:52px;height:52px;border-radius:8px;object-fit:cover;border:1px solid var(--border)" onerror="this.src='https://picsum.photos/seed/${i.id}/100/100'">
          <div style="flex:1">
            <div style="font-size:var(--text-sm);font-weight:600">${i.name}</div>
            <div style="font-size:var(--text-xs);color:var(--text-muted)">${i.variant || ''} × ${i.qty}</div>
          </div>
          <div style="font-weight:700;color:var(--maroon)">${formatPrice(i.price * i.qty)}</div>
        </div>`).join('')}
    </div>
    <hr style="border-color:var(--border-light);margin:12px 0">
    <div class="summary-row"><span>Subtotal</span><span>${formatPrice(subtotal)}</span></div>
    <div class="summary-row"><span>Delivery</span><span>${delivery === 0 ? '<b style="color:var(--color-success)">FREE</b>' : formatPrice(delivery)}</span></div>
    <div class="summary-row total"><span>Total</span><span>${formatPrice(total)}</span></div>`;
}
function initCheckoutForm() {
  const form = document.getElementById('checkout-form');
  if (!form) return;
  document.querySelectorAll('.delivery-option').forEach(opt => {
    opt.addEventListener('click', () => {
      document.querySelectorAll('.delivery-option').forEach(o => o.classList.remove('selected'));
      opt.classList.add('selected');
      opt.querySelector('input[type="radio"]').checked = true;
      updateSubmitButton(opt.dataset.method);
    });
  });
  form.addEventListener('submit', e => {
    e.preventDefault();
    submitOrder(form);
  });
}
function updateSubmitButton(method) {
  const btn = document.getElementById('submit-order-btn');
  if (!btn) return;
  if (method === 'whatsapp') {
    btn.innerHTML = '<i class="fab fa-whatsapp"></i> Send Order via WhatsApp';
    btn.className = 'btn btn-whatsapp btn-lg w-100';
  } else if (method === 'call') {
    btn.innerHTML = '<i class="fas fa-phone-alt"></i> Call to Confirm Order';
    btn.className = 'btn btn-secondary btn-lg w-100';
  } else {
    btn.innerHTML = '<i class="fas fa-store"></i> Reserve for Store Pickup';
    btn.className = 'btn btn-outline btn-lg w-100';
  }
}
function submitOrder(form) {
  const name    = form.querySelector('#name').value.trim();
  const phone   = form.querySelector('#phone').value.trim();
  const address = form.querySelector('#address')?.value.trim() || '';
  const method  = document.querySelector('.delivery-option.selected')?.dataset.method || 'whatsapp';
  const note    = form.querySelector('#order-note')?.value.trim() || '';
  if (!name || !phone) {
    showToast('⚠️ Please fill in your name and phone number.', 'error');
    return;
  }
  if (!/^[6-9]\d{9}$/.test(phone.replace(/\D/g,''))) {
    showToast('⚠️ Please enter a valid 10-digit mobile number.', 'error');
    return;
  }
  Cart.load();
  if (Cart.items.length === 0) {
    showToast('Cart is empty!', 'error');
    return;
  }
  const subtotal = Cart.total();
  const delivery = subtotal >= 599 ? 0 : 60;
  const total    = subtotal + delivery;
  if (method === 'whatsapp') {
    let msg = `🕉️ *New Order — Sri Manikanta Pooja Stores*\n\n`;
    msg += `👤 *Customer:* ${name}\n📞 *Phone:* ${phone}\n`;
    if (address) msg += `📍 *Address:* ${address}\n`;
    msg += `\n🛒 *Order Details:*\n`;
    Cart.items.forEach(i => {
      msg += `• ${i.name}${i.variant ? ` (${i.variant})` : ''} × ${i.qty} = ${formatPrice(i.price * i.qty)}\n`;
    });
    msg += `\n🚚 *Delivery:* ${delivery === 0 ? 'FREE' : formatPrice(delivery)}`;
    msg += `\n💰 *Total: ${formatPrice(total)}*`;
    if (note) msg += `\n📝 *Note:* ${note}`;
    msg += `\n\nPlease confirm my order. Thank you! 🙏`;
    window.open(`https://wa.me/${STORE.whatsapp}?text=${encodeURIComponent(msg)}`, '_blank');
  } else if (method === 'call') {
    window.location.href = `tel:${STORE.phone1}`;
  }
  Cart.clear();
  showOrderSuccess(name);
}
function showOrderSuccess(name) {
  const main = document.querySelector('.checkout-main');
  if (!main) return;
  main.innerHTML = `
    <div class="order-success">
      <div class="success-icon">🙏</div>
      <h2 style="font-family:var(--font-heading);color:var(--maroon);font-size:2rem;margin-bottom:12px">Order Sent!</h2>
      <p style="font-size:var(--text-lg);color:var(--text-muted);margin-bottom:8px">
        Thank you, <strong>${name}</strong>! Your order has been sent via WhatsApp.
      </p>
      <p style="color:var(--text-muted);margin-bottom:32px">
        Our team will confirm your order and delivery details shortly.<br>
        <strong>Store: +91 98499 85423</strong>
      </p>
      <div style="display:flex;gap:16px;justify-content:center;flex-wrap:wrap">
        <a href="index.html" class="btn btn-primary btn-lg"><i class="fas fa-home"></i> Go to Home</a>
        <a href="shop.html" class="btn btn-outline btn-lg"><i class="fas fa-store"></i> Continue Shopping</a>
      </div>
    </div>`;
}